import React, { useEffect, useState, useRef } from "react";
import EditorShell from "./shared/EditorShell";
import BaseQuestionFields from "./shared/BaseQuestionFields";
import FAWCheckbox from "../../../../component-widget/FAWCheckbox";
import FAWToast from "../../../../component-widget/FAWToast";

export default function QueLabelItemEditor({ data, onClose, onSave, saveRef, isDefaultLanguage = true, isDeployed = false }) {

  const [item, setItem] = useState(
    data || {
      name: "",
      text: "",
      required: false,
      validationMessage: "",
      horizontalLine: false,
      boldInPdf: false,
      hideInPdf: false,
    }
  );

  // Track user-edited name to prevent it from being cleared by CKEditor changes
  const userEditedNameRef = useRef(null);
  const [toast, setToast] = useState({ open: false, message: '', type: 'info', duration: 3000 });

  useEffect(() => {
    if (data) {
      setItem(prev => {
        const updatedItem = { ...prev, ...data };
        
        // If we have a user-edited name, preserve it
        if (userEditedNameRef.current !== null) {
          updatedItem.name = userEditedNameRef.current;
        }
        
        return updatedItem;
      });
    }
  }, [data]);

  const handleNameChange = (newItem) => {
    // Check if this is a name field change (user editing the name field)
    const isNameFieldChange = newItem.name !== item.name;
    
    // If user has edited the name AND this is not a name field change (e.g., CKEditor change),
    // then preserve the user-edited name
    if (userEditedNameRef.current !== null && !isNameFieldChange) {
      newItem.name = userEditedNameRef.current;
    }
    
    setItem(newItem);
    
    // Track that user has manually edited the name
    // Only set userEditedName if the new name is different from the original data name
    if (newItem.name !== data?.name) {
      userEditedNameRef.current = newItem.name;
    } 
  };

  const handleSave = () => {
    // Prevent save if version is deployed
    if (isDeployed) {
      setToast({ open: true, message: "You cannot save this item since it is a part of a currently active version", type: 'error', duration: 5000 });
      return;
    } 
    onSave?.(item); 
  };

  return (
    <EditorShell onSave={handleSave} onClose={onClose} saveRef={saveRef}>
      <BaseQuestionFields 
        item={item} 
        onChange={handleNameChange} 
        isDefaultLanguage={isDefaultLanguage}
        isDeployed={isDeployed}
        suppressValidation={true}
        questionType="LabelItemType"
      />
      <div style={{ display: "flex", flexDirection: "column", gap: 16, marginTop: 16 }}>
        <FAWCheckbox 
          label="Bold in PDF"
          checked={!!item.boldInPdf} 
          onChange={(e)=> setItem(prev=>({ ...prev, boldInPdf: e.target.checked }))}
          labelStyle={{ fontSize: '12px' }}
        />
        <FAWCheckbox 
          label="Hide in PDF"
          checked={!!item.hideInPdf} 
          onChange={(e)=> setItem(prev=>({ ...prev, hideInPdf: e.target.checked }))}
          labelStyle={{ fontSize: '12px' }}
        />
      </div>
      <FAWToast 
        open={toast.open} 
        message={toast.message} 
        type={toast.type}
        duration={toast.duration}
        onClose={() => setToast({ open: false, message: '', type: 'info', duration: 3000 })}
      />
    </EditorShell>
  );
}